func solve(nums []int64) []int64 {
	n := len(nums)
	ans := make([]int64, 2*n)

	// Copy the first n elements
	for i := 0; i < n; i++ {
		ans[i] = nums[i]
	}

	// Fill the last n elements with the reverse of nums
	for i := 0; i < n; i++ {
		// ans[i + n] should be nums[n - 1 - i]
		ans[i+n] = nums[n-1-i]
	}

	return ans
}
